data.migrationiderror#MigrationIDError:
Wraps an error with the migration ID that caused it:
var idErr migrations.MigrationIDError
if errors.As(err, &idErr) {
    fmt.Printf("migration %s failed\n", idErr.MigrationID())
}

data.migrationerror#MigrationError:
Wraps an error with the full Migration object:
var migErr migrations.MigrationError
if errors.As(err, &migErr) {
    m := migErr.Migration()
    fmt.Printf("migration %s (%s) failed\n", m.ID(), m.Description())
}

data.queryerror#QueryError:
Wraps SQL execution errors with the query text that failed:
var qErr migrations.QueryError
if errors.As(err, &qErr) {
    fmt.Printf("query failed: %s\n", qErr.Query())
}
This is particularly useful for debugging SQL migration failures, since you can see exactly which statement caused the error.

data.interface#Interface:
type Planner interface {
    Plan(ctx context.Context) (Plan, error)
}
type Plan []*Action
type Action struct {
    Action    ActionType  // "do" or "undo"
    Migration Migration
}

data.stepplanner#StepPlanner:
Steps forward or backward by N migrations.
// Apply the next 3 pending migrations
migrations.Migrate(ctx, source, target,
    migrations.WithPlanner(migrations.StepPlanner(3)),
)
// Undo the last 2 applied migrations
migrations.Migrate(ctx, source, target,
    migrations.WithPlanner(migrations.StepPlanner(-2)),
)
Returns ErrStepOutOfIndex if the step goes beyond the available range.

data.interface#Interface:
type RunnerReporter interface {
    BeforeExecute(ctx context.Context, info *BeforeExecuteInfo)
    BeforeExecuteMigration(ctx context.Context, info *BeforeExecuteMigrationInfo)
    AfterExecuteMigration(ctx context.Context, info *AfterExecuteMigrationInfo)
    AfterExecute(ctx context.Context, info *AfterExecuteInfo)
}

data.usage#Usage:
Pass a reporter through WithRunnerOptions:
migrations.Migrate(ctx, source, target,
    migrations.WithRunnerOptions(
        migrations.WithReporter(reporter),
    ),
)
Or when creating a runner directly:
runner := migrations.NewRunner(source, target,
    migrations.WithReporter(reporter),
)

data.custom-reporters#Custom Reporters:
Implement the RunnerReporter interface to build your own:
type metricsReporter struct {
    // your metrics client
}
func (r *metricsReporter) BeforeExecute(ctx context.Context, info *migrations.BeforeExecuteInfo) {
    // record that migrations are starting
}
func (r *metricsReporter) BeforeExecuteMigration(ctx context.Context, info *migrations.BeforeExecuteMigrationInfo) {
    // start a timer for this migration
}
func (r *metricsReporter) AfterExecuteMigration(ctx context.Context, info *migrations.AfterExecuteMigrationInfo) {
    // record duration, success/failure
}
func (r *metricsReporter) AfterExecute(ctx context.Context, info *migrations.AfterExecuteInfo) {
    // record total count, overall result
}

data.interface#Interface:
type Source interface {
    Add(ctx context.Context, migration Migration) error
    Load(ctx context.Context) (Repository, error)
}
Add registers a migration with the source. Returns ErrMigrationAlreadyExists if a migration with the same ID is already registered.
Load returns a Repository containing all available migrations, sorted by ID (oldest first).

data.sql-files-embedfs#SQL Files (embed.FS):
Load migrations from embedded SQL files using SourceFromFS:
import migrationsql "github.com/jamillosantos/migrations/v2/sql"
//go:embed migrations/*.sql
var migrationsFS embed.FS
source, err := migrationsql.SourceFromFS(func() migrationsql.DBExecer {
    return db
}, migrationsFS, "migrations")
The dbGetter function is called each time a migration runs. This lets you control which connection or transaction is used for execution.A pgx-native equivalent is available in the pgx package:
import migrationpgx "github.com/jamillosantos/migrations/v2/pgx"
source, err := migrationpgx.SourceFromFS(func() migrationpgx.PgxDB {
    return conn
}, migrationsFS, "migrations")
You can also load from a directory on disk instead of an embedded filesystem:
source, err := migrationsql.SourceFromDirectory(func() migrationsql.DBExecer {
    return db
}, "./migrations")

data.go-functions-fnc#Go Functions (fnc):
For migrations that need to do more than run SQL — call APIs, transform data, coordinate between services:
import "github.com/jamillosantos/migrations/v2/fnc"
// Forward-only migration
m := fnc.Migration(func(ctx context.Context) error {
    // your migration logic
    return nil
})
// Bidirectional migration
m := fnc.Migration2(
    func(ctx context.Context) error { /* do */ return nil },
    func(ctx context.Context) error { /* undo */ return nil },
)
The fnc package extracts the migration ID and description from the calling file's name. A file named 20250401120000_seed_initial_data.go produces a migration with ID 20250401120000 and description seed initial data.Options:
fnc.WithSkip(n) — Skip N stack frames when resolving the caller filename. Useful when wrapping fnc.Migration in a helper function. Default: 1.
fnc.WithSource(source) — Automatically register the migration with a source when it's created.

data.combining-sources#Combining Sources:
SQL file migrations and Go function migrations can coexist in the same source. Add function-based migrations to an SQL source:
source, _ := migrationsql.SourceFromFS(dbGetter, migrationsFS, "migrations")
for _, m := range codeMigrations {
    source.Add(ctx, m)
}
All migrations are sorted by ID (timestamp) regardless of their type, so they execute in chronological order.

data.full-example#Full Example:
package main
import (
	"context"
	"log"
	"github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/service/dynamodb"
	"github.com/jamillosantos/migrations/v2"
	"github.com/jamillosantos/migrations/v2/fnc"
	migrationsdynamo "github.com/jamillosantos/migrations-dynamodb"
)
func main() {
	ctx := context.Background()
	cfg, err := config.LoadDefaultConfig(ctx)
	if err != nil {
		log.Fatal(err)
	}
	client := dynamodb.NewFromConfig(cfg)
	// Create source with Go function migrations
	source := migrations.NewMemorySource()
	source.Add(ctx, fnc.Migration(func(ctx context.Context) error {
		// Create your application tables, indexes, etc.
		_, err := client.CreateTable(ctx, &dynamodb.CreateTableInput{
			// ...
		})
		return err
	}))
	// Create DynamoDB target
	target := migrationsdynamo.NewTarget(client)
	_, err = migrations.Migrate(ctx, source, target)
	if err != nil {
		log.Fatal(err)
	}
}

package main
import (
	"context"
	"log"
	"time"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
	"github.com/jamillosantos/migrations/v2"
	"github.com/jamillosantos/migrations/v2/fnc"
	migrationsmongo "github.com/jamillosantos/migrations-mongo/v2"
)
func main() {
	ctx := context.Background()
	client, err := mongo.Connect(options.Client().ApplyURI("mongodb://localhost:27017"))
	if err != nil {
		log.Fatal(err)
	}
	defer client.Disconnect(ctx)
	db := client.Database("myapp")
	// Create source with Go function migrations
	source := migrations.NewMemorySource()
	// Register migrations — the fnc package extracts the ID from the filename
	// File: 20250401120000_create_users_collection.go
	source.Add(ctx, fnc.Migration(func(ctx context.Context) error {
		return db.CreateCollection(ctx, "users")
	}))
	// Create MongoDB target
	target, err := migrationsmongo.NewTarget(db,
		migrationsmongo.LockTimeout(30 * time.Second),
	)
	if err != nil {
		log.Fatal(err)
	}
	_, err = migrations.Migrate(ctx, source, target)
	if err != nil {
		log.Fatal(err)
	}
}

data.migration-pattern#Migration Pattern:
Since MongoDB migrations are Go functions, a common pattern is to create a migrations package with a helper:
// migrations/migrations.go
package mymigrations
import (
	"context"
	"github.com/jamillosantos/migrations/v2"
	"github.com/jamillosantos/migrations/v2/fnc"
	"go.mongodb.org/mongo-driver/v2/mongo"
)
var (
	Migrations []migrations.Migration
	DB         *mongo.Database
)
func migration(do func(ctx context.Context) error) {
	Migrations = append(Migrations, fnc.Migration(do, fnc.WithSkip(2)))
}
// migrations/20250401120000_create_users.go
package mymigrations
import (
	"context"
	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)
var _ = migration(func(ctx context.Context) error {
	if err := DB.CreateCollection(ctx, "users"); err != nil {
		return err
	}
	_, err := DB.Collection("users").Indexes().CreateOne(ctx, mongo.IndexModel{
		Keys:    bson.D{{Key: "email", Value: 1}},
		Options: options.Index().SetUnique(true),
	})
	return err
})
Then in your main:
mymigrations.DB = db
source := migrations.NewMemorySource()
for _, m := range mymigrations.Migrations {
    source.Add(ctx, m)
}

